import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './Home.css';

const CATEGORIES = ['All', 'Medical', 'Education', 'Social', 'Environment', 'Animal Welfare', 'Disaster Relief', 'Other'];

const CampaignCard = ({ campaign }) => {
  const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
  const daysAgo = Math.floor((Date.now() - new Date(campaign.createdAt)) / (1000 * 60 * 60 * 24));

  return (
    <Link to={`/campaigns/${campaign._id}`} className="campaign-card" id={`campaign-card-${campaign._id}`}>
      <div className="campaign-image-wrapper">
        {campaign.imageUrl ? (
          <img
            src={campaign.imageUrl}
            alt={campaign.title}
            className="campaign-image"
            onError={(e) => {
              e.target.onerror = null;
              e.target.src = `https://picsum.photos/seed/${campaign._id}/600/340`;
            }}
          />
        ) : (
          <div className="campaign-image-placeholder">
            {campaign.category === 'Medical' ? '🏥' :
             campaign.category === 'Education' ? '📚' :
             campaign.category === 'Social' ? '🤝' :
             campaign.category === 'Environment' ? '🌿' :
             campaign.category === 'Animal Welfare' ? '🐾' :
             campaign.category === 'Disaster Relief' ? '⛑️' : '💡'}
          </div>
        )}
        <span className="campaign-category-badge">{campaign.category}</span>
      </div>

      <div className="campaign-card-body">
        <h3 className="campaign-title">{campaign.title}</h3>
        <p className="campaign-desc">
          {campaign.description.length > 100
            ? campaign.description.substring(0, 100) + '...'
            : campaign.description}
        </p>

        <div className="campaign-progress">
          <div className="progress-bar-wrapper">
            <div
              className="progress-bar-fill"
              style={{ width: `${progress}%` }}
              role="progressbar"
              aria-valuenow={progress}
              aria-valuemin="0"
              aria-valuemax="100"
            ></div>
          </div>
          <div className="campaign-progress-labels">
            <span className="raised-amount">
              ₹{campaign.raised.toLocaleString('en-IN')} raised
            </span>
            <span className="progress-pct">{progress}%</span>
          </div>
        </div>

        <div className="campaign-meta">
          <div className="campaign-goal">
            Goal: <strong>₹{campaign.goal.toLocaleString('en-IN')}</strong>
          </div>
          <div className="campaign-info">
            <span className="creator-name">
              By {campaign.creator?.name || 'Anonymous'}
            </span>
            <span className="campaign-age">
              {daysAgo === 0 ? 'Today' : `${daysAgo}d ago`}
            </span>
          </div>
        </div>
      </div>
    </Link>
  );
};

const Home = () => {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);

  const fetchCampaigns = useCallback(async () => {
    try {
      setLoading(true);
      setError('');

      const params = { page, limit: 9 };
      if (activeCategory !== 'All') params.category = activeCategory;
      if (search.trim()) params.search = search.trim();

      const { data } = await axios.get('/api/campaigns', { params });
      setCampaigns(data.campaigns);
      setTotalPages(data.totalPages);
      setTotal(data.total);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load campaigns. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [page, activeCategory, search]);

  useEffect(() => {
    const timer = setTimeout(fetchCampaigns, 300);
    return () => clearTimeout(timer);
  }, [fetchCampaigns]);

  const handleCategoryChange = (cat) => {
    setActiveCategory(cat);
    setPage(1);
  };

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero-section" id="hero">
        <div className="hero-bg">
          <div className="hero-orb hero-orb-1"></div>
          <div className="hero-orb hero-orb-2"></div>
          <div className="hero-grid"></div>
        </div>
        <div className="container hero-content">
          <div className="hero-badge">💜 Powered by Community</div>
          <h1 className="hero-title">
            Fund Causes That <br />
            <span className="gradient-text">Change Lives</span>
          </h1>
          <p className="hero-subtitle">
            Join thousands of donors supporting medical emergencies, education,
            social initiatives, and more across India.
          </p>
          <div className="hero-cta">
            <Link to="/create-campaign" className="btn btn-primary btn-lg" id="hero-start-btn">
              🚀 Start a Campaign
            </Link>
            <a href="#campaigns-section" className="btn btn-secondary btn-lg" id="hero-explore-btn">
              Explore Causes
            </a>
          </div>
          <div className="hero-stats">
            <div className="hero-stat">
              <span className="stat-number">10K+</span>
              <span className="stat-label">Campaigns</span>
            </div>
            <div className="hero-stat-divider"></div>
            <div className="hero-stat">
              <span className="stat-number">₹50Cr+</span>
              <span className="stat-label">Raised</span>
            </div>
            <div className="hero-stat-divider"></div>
            <div className="hero-stat">
              <span className="stat-number">1M+</span>
              <span className="stat-label">Donors</span>
            </div>
          </div>
        </div>
      </section>

      {/* Campaigns Section */}
      <section className="campaigns-section" id="campaigns-section">
        <div className="container">
          {/* Search Bar */}
          <div className="search-wrapper" id="search-wrapper">
            <input
              type="text"
              id="campaign-search"
              className="search-input"
              placeholder="🔍  Search campaigns by title or description..."
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
              aria-label="Search campaigns"
            />
          </div>

          {/* Category Filters */}
          <div className="category-filters" id="category-filters" role="tablist">
            {CATEGORIES.map((cat) => (
              <button
                key={cat}
                id={`cat-filter-${cat.toLowerCase().replace(' ', '-')}`}
                className={`category-btn ${activeCategory === cat ? 'category-btn-active' : ''}`}
                onClick={() => handleCategoryChange(cat)}
                role="tab"
                aria-selected={activeCategory === cat}
              >
                {cat}
              </button>
            ))}
          </div>

          {/* Results Count */}
          {!loading && (
            <p className="results-count" id="results-count">
              {total === 0 ? 'No campaigns found' : `${total} campaign${total !== 1 ? 's' : ''} found`}
            </p>
          )}

          {/* Campaign Grid */}
          {loading ? (
            <div className="loading-state">
              <div className="spinner spinner-lg"></div>
              <p>Loading campaigns...</p>
            </div>
          ) : error ? (
            <div className="alert alert-error" id="campaigns-error">
              <span>⚠️</span>
              <p>{error}</p>
            </div>
          ) : campaigns.length === 0 ? (
            <div className="empty-state" id="empty-campaigns">
              <div className="empty-icon">🔍</div>
              <h3>No campaigns found</h3>
              <p>Try a different search term or category filter.</p>
              <Link to="/create-campaign" className="btn btn-primary" id="empty-create-btn">
                Start the first campaign
              </Link>
            </div>
          ) : (
            <div className="campaigns-grid" id="campaigns-grid">
              {campaigns.map((campaign) => (
                <CampaignCard key={campaign._id} campaign={campaign} />
              ))}
            </div>
          )}

          {/* Pagination */}
          {!loading && totalPages > 1 && (
            <div className="pagination" id="pagination">
              <button
                className="btn btn-secondary btn-sm"
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                id="btn-prev-page"
              >
                ← Previous
              </button>
              <span className="pagination-info">
                Page {page} of {totalPages}
              </span>
              <button
                className="btn btn-secondary btn-sm"
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                id="btn-next-page"
              >
                Next →
              </button>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Home;
